import { isArray } from 'lodash-es';
import type { PaddingOptions } from 'maplibre-gl';

import { FIT_BOUNDS_OPTIONS } from '../constants.js';
import type { BoundingBoxCoords, ViewState } from '../types/map-view.js';

export type InitialBounds = {
  bounds: BoundingBoxCoords;
  fitBoundsOptions: {
    padding: number | PaddingOptions;
  };
};

export const toMapBoxInitialViewState = (
  initialViewState: ViewState | BoundingBoxCoords,
): ViewState | InitialBounds =>
  isArray(initialViewState)
    ? { bounds: initialViewState, fitBoundsOptions: FIT_BOUNDS_OPTIONS }
    : initialViewState;
